import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function Checkout({ token }) {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    phone: '',
    address: '',
    city: '',
    province: '',
    postalCode: ''
  });

  const navigate = useNavigate();

  useEffect(() => {
    fetchCart();
  }, []);

  const fetchCart = async () => {
    try {
      const res = await axios.get('/api/cart', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setCart({ items: res.data });
    } catch (err) {
      setError('Failed to load cart');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleCheckout = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/orders/checkout', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSuccess('Order placed successfully!');
      setTimeout(() => {
        navigate('/orders');
      }, 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Checkout failed');
    }
  };

  if (loading) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif' }}>Loading...</div>;

  const total = cart?.items.reduce((sum, item) => sum + (item.price || item.productDetails?.price || 0) * item.quantity, 0) || 0;

  const inputStyle = {
    width: '100%',
    padding: '12px 10px',
    border: '1px solid #f0f0f0',
    fontSize: '13px',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: '#000',
    boxSizing: 'border-box'
  };

  const labelStyle = {
    display: 'block',
    fontSize: '11px',
    fontWeight: '400',
    letterSpacing: '0.5px',
    textTransform: 'uppercase',
    color: '#999',
    marginBottom: '8px'
  };

  return (
    <div style={{
      padding: '60px 50px',
      backgroundColor: '#fff',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      <h1 style={{
        fontSize: '28px',
        fontWeight: '300',
        letterSpacing: '1px',
        color: '#000',
        margin: '0 0 40px 0',
        textTransform: 'uppercase'
      }}>
        CHECKOUT
      </h1>

      {error && (
        <div style={{
          padding: '12px',
          backgroundColor: '#ffebee',
          color: '#d32f2f',
          fontSize: '12px',
          marginBottom: '30px',
          letterSpacing: '0.5px'
        }}>
          {error}
        </div>
      )}

      {success && (
        <div style={{
          padding: '12px',
          backgroundColor: '#f0f0f0',
          color: '#000',
          fontSize: '12px',
          marginBottom: '30px',
          letterSpacing: '0.5px'
        }}>
          {success}
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '60px' }}>
        {/* Shipping Form */}
        <form onSubmit={handleCheckout}>
          <h3 style={{
            fontSize: '13px',
            fontWeight: '400',
            letterSpacing: '0.5px',
            color: '#000',
            margin: '0 0 30px 0',
            textTransform: 'uppercase'
          }}>
            SHIPPING ADDRESS
          </h3>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Full Name *</label>
            <input
              type="text"
              name="fullName"
              value={formData.fullName}
              onChange={handleChange}
              required
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Email *</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Phone *</label>
            <input
              type="tel"
              name="phone"
              value={formData.phone}
              onChange={handleChange}
              required
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Address *</label>
            <textarea
              name="address"
              value={formData.address}
              onChange={handleChange}
              required
              rows="3"
              style={{
                ...inputStyle,
                resize: 'vertical'
              }}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>City *</label>
            <input
              type="text"
              name="city"
              value={formData.city}
              onChange={handleChange}
              required
              style={inputStyle}
            />
          </div>

          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: '15px',
            marginBottom: '20px'
          }}>
            <div>
              <label style={labelStyle}>Province *</label>
              <input
                type="text"
                name="province"
                value={formData.province}
                onChange={handleChange}
                required
                style={inputStyle}
              />
            </div>
            <div>
              <label style={labelStyle}>Postal Code *</label>
              <input
                type="text"
                name="postalCode"
                value={formData.postalCode}
                onChange={handleChange}
                required
                style={inputStyle}
              />
            </div>
          </div>

          <button
            type="submit"
            style={{
              width: '100%',
              padding: '15px',
              backgroundColor: '#000',
              color: '#fff',
              border: 'none',
              fontSize: '12px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              transition: 'opacity 0.3s'
            }}
            onMouseEnter={(e) => e.target.style.opacity = '0.8'}
            onMouseLeave={(e) => e.target.style.opacity = '1'}
          >
            COMPLETE ORDER
          </button>
        </form>

        {/* Order Summary */}
        <div>
          <h3 style={{
            fontSize: '13px',
            fontWeight: '400',
            letterSpacing: '0.5px',
            color: '#000',
            margin: '0 0 30px 0',
            textTransform: 'uppercase'
          }}>
            ORDER SUMMARY
          </h3>

          <div style={{
            backgroundColor: '#f9f9f9',
            padding: '20px',
            marginBottom: '30px'
          }}>
            {cart?.items.map(item => (
              <div key={item.productId} style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontSize: '12px',
                fontWeight: '300',
                color: '#666',
                letterSpacing: '0.3px',
                paddingBottom: '15px',
                marginBottom: '15px',
                borderBottom: '1px solid #f0f0f0'
              }}>
                <div>
                  <div style={{ color: '#000', marginBottom: '5px' }}>
                    {item.productDetails?.name || 'Product'}
                  </div>
                  <div>Qty: {item.quantity}</div>
                </div>
                <div style={{ textAlign: 'right', color: '#000' }}>
                  ${((item.price || item.productDetails?.price || 0) * item.quantity).toFixed(2)}
                </div>
              </div>
            ))}
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            fontSize: '13px',
            fontWeight: '300',
            color: '#666',
            letterSpacing: '0.3px',
            paddingBottom: '15px',
            marginBottom: '15px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <span>Subtotal</span>
            <span>${total.toFixed(2)}</span>
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            fontSize: '13px',
            fontWeight: '300',
            color: '#666',
            letterSpacing: '0.3px',
            paddingBottom: '15px',
            marginBottom: '15px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <span>Shipping</span>
            <span>Calculated at checkout</span>
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            fontSize: '14px',
            fontWeight: '400',
            color: '#000',
            letterSpacing: '0.5px'
          }}>
            <span>TOTAL</span>
            <span>${total.toFixed(2)}</span>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Checkout;
